#include <stdio.h>
#include <stdlib.h>
#define MAXN 200005
#define MAXQ 200005
long long dp[MAXN][MAXQ];
int N, Q;
int edges[MAXN][2];
long long X0[MAXN];
void compute(int node, int day) {
    if (day == 0) {
        dp[node][day] = X0[node];
    } else {
        long long xor = 0;
        for (int i = 0; i < N - 1; i++) {
            if (edges[i][0] == node) {
                compute(edges[i][1], day - 1);
                xor ^= dp[edges[i][1]][day - 1];
            } else if (edges[i][1] == node) {
                compute(edges[i][0], day - 1);
                xor ^= dp[edges[i][0]][day - 1];
            }
        }
        dp[node][day] = xor;
    }
}
int main() {
    scanf("%d %d", &N, &Q);
    for (int i = 0; i < N - 1; i++) {
        scanf("%d %d", &edges[i][0], &edges[i][1]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%lld", &X0[i]);
    }
    for (int i = 0; i < Q; i++) {
        int delta;
        scanf("%d", &delta);
        compute(0, delta);
        printf("%lld\n", dp[0][delta]);
    }
    return 0;
}

