#include <iostream>
#include <vector>
using namespace std;
const int MAXN = 200005;
const int MAXQ = 200005;
long long dp[MAXN][MAXQ];
int N, Q;
vector<pair<int, int>> edges;
long long X0[MAXN];
void compute(int node, int day) {
    if (day == 0) {
        dp[node][day] = X0[node];
    } else {
        long long xor = 0;
        for (auto edge : edges) {
            if (edge.first == node) {
                compute(edge.second, day - 1);
                xor ^= dp[edge.second][day - 1];
            } else if (edge.second == node) {
                compute(edge.first, day - 1);
                xor ^= dp[edge.first][day - 1];
            }
        }
        dp[node][day] = xor;
    }
}
int main() {
    cin >> N >> Q;
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        cin >> u >> v;
        edges.push_back({u, v});
    }
    for (int i = 0; i < N; i++) {
        cin >> X0[i];
    }
    for (int i = 0; i < Q; i++) {
        int delta;
        cin >> delta;
        compute(0, delta);
        cout << dp[0][delta] << endl;
    }
    return 0;
}

