import java.util.Scanner;
public class Main {
    static final int MAXN = 200005;
    static final int MAXQ = 200005;
    static long[][] dp = new long[MAXN][MAXQ];
    static int N, Q;
    static int[][] edges;
    static long[] X0;
    public static void compute(int node, int day) {
        if (day == 0) {
            dp[node][day] = X0[node];
        } else {
            long xor = 0;
            for (int i = 0; i < N - 1; i++) {
                if (edges[i][0] == node) {
                    compute(edges[i][1], day - 1);
                    xor ^= dp[edges[i][1]][day - 1];
                } else if (edges[i][1] == node) {
                    compute(edges[i][0], day - 1);
                    xor ^= dp[edges[i][0]][day - 1];
                }
            }
            dp[node][day] = xor;
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        N = scanner.nextInt();
        Q = scanner.nextInt();
        edges = new int[N - 1][2];
        for (int i = 0; i < N - 1; i++) {
            edges[i][0] = scanner.nextInt();
            edges[i][1] = scanner.nextInt();
        }
        X0 = new long[N];
        for (int i = 0; i < N; i++) {
            X0[i] = scanner.nextLong();
        }
        for (int i = 0; i < Q; i++) {
            int delta = scanner.nextInt();
            compute(0, delta);
            System.out.println(dp[0][delta]);
        }
    }
}

